#!/usr/bin/env python3
import requests
import json

# 飞书应用凭证
APP_ID = "cli_a929838abb389bc6"
APP_SECRET = "3vasdyspNoUPXCL6TniyLdkQbLqmPqEU"

# 1. 获取 tenant_access_token
def get_tenant_token():
    url = "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal"
    payload = {
        "app_id": APP_ID,
        "app_secret": APP_SECRET
    }
    response = requests.post(url, json=payload)
    if response.status_code == 200:
        return response.json()["tenant_access_token"]
    else:
        print(f"获取token失败: {response.text}")
        return None

# 2. 分页获取所有用户列表
def get_all_users(token):
    url = "https://open.feishu.cn/open-apis/contact/v3/users"
    headers = {
        "Authorization": f"Bearer {token}"
    }
    all_users = []
    page_token = ""
    has_more = True

    while has_more:
        params = {
            "page_size": 50,
            "user_id_type": "open_id",
            "page_token": page_token
        }
        response = requests.get(url, headers=headers, params=params)
        if response.status_code == 200:
            data = response.json()
            if data["code"] == 0:
                all_users.extend(data["data"]["items"])
                has_more = data["data"]["has_more"]
                page_token = data["data"].get("page_token", "")
            else:
                print(f"获取用户列表失败: {data['msg']}")
                break
        else:
            print(f"请求失败: {response.text}")
            break
    return all_users

if __name__ == "__main__":
    token = get_tenant_token()
    if not token:
        exit(1)

    # 获取所有用户
    all_users = get_all_users(token)
    print(f"企业总用户数: {len(all_users)}")
    print("=" * 50)

    # 查找王总
    target_mobile = "13543852612"
    target_name = "王总"

    found = []
    for user in all_users:
        # 匹配手机号（去掉+86匹配）
        user_mobile = user["mobile"].replace("+86", "") if user["mobile"] else ""
        # 匹配姓名
        if (user_mobile == target_mobile) or (target_name in user["name"]):
            found.append(user)

    if found:
        print(f"找到匹配的用户 {len(found)} 个:")
        for i, user in enumerate(found):
            print(f"\n用户{i+1}:")
            print(f"姓名: {user['name']}")
            print(f"手机号: {user['mobile']}")
            print(f"open_id: {user['open_id']}")
            print(f"用户ID: {user['user_id']}")
            print(f"状态: {'已激活' if user['status']['is_activated'] else '未激活'}")
    else:
        print("未找到匹配的王总用户，所有用户列表如下：")
        for user in all_users:
            print(f"姓名: {user['name']}, 手机号: {user['mobile']}, open_id: {user['open_id']}")

