#!/usr/bin/env python3
import requests
import json

# 飞书应用凭证
APP_ID = "cli_a929838abb389bc6"
APP_SECRET = "3vasdyspNoUPXCL6TniyLdkQbLqmPqEU"

def get_tenant_token():
    url = "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal"
    payload = {"app_id": APP_ID, "app_secret": APP_SECRET}
    response = requests.post(url, json=payload)
    return response.json()["tenant_access_token"] if response.status_code == 200 else None

def create_public_group(token):
    """创建公开可加入的群聊"""
    url = "https://open.feishu.cn/open-apis/im/v1/chats"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json; charset=utf-8"
    }
    payload = {
        "name": "研发项目工作群",
        "chat_mode": "group",
        "join_message_visibility": "all_members",
        "leave_message_visibility": "all_members",
        "membership_approval": "no_approval",  # 不需要审核，任何人都可以加入
        "edit_permission": "all_members",
        "share_permission": "all_members",
        "add_member_permission": "all_members",
        "at_all_permission": "all_members"
    }
    response = requests.post(url, headers=headers, json=payload)
    if response.status_code == 200:
        data = response.json()
        if data["code"] == 0:
            chat_id = data['data']['chat_id']
            print(f"✅ 公开群创建成功！群ID：{chat_id}")
            # 生成群链接
            group_link = f"https://applink.feishu.cn/client/chat/chatter/{chat_id}"
            print(f"群加入链接：{group_link}")
            return chat_id, group_link
        else:
            print(f"创建失败：{data['msg']}")
            return None, None
    else:
        print(f"请求失败: {response.status_code}, {response.text}")
        return None, None

def send_group_link(token, chat_id, group_link):
    """把群链接发到全员群"""
    url = "https://open.feishu.cn/open-apis/im/v1/messages"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json; charset=utf-8"
    }
    params = {"receive_id_type": "chat_id"}
    payload = {
        "receive_id": "oc_c74d25c984ead08293cca215d31f00b5",
        "msg_type": "text",
        "content": json.dumps({"text": f"👉 研发项目工作群已创建完成，请点击链接加入：\n{group_link}\n无需审核，点击即可加入。"})
    }
    response = requests.post(url, headers=headers, params=params, json=payload)
    if response.status_code == 200 and response.json()["code"] == 0:
        print("✅ 群链接已发送到全员群")
        return True
    else:
        print(f"发送失败：{response.text}")
        return False

if __name__ == "__main__":
    token = get_tenant_token()
    if token:
        chat_id, group_link = create_public_group(token)
        if chat_id and group_link:
            send_group_link(token, chat_id, group_link)
            print("\n🎉 全部完成！您和王总现在就可以在全员群里点击链接加入新群了")

