#!/usr/bin/env python3
import requests
import json

# 飞书应用凭证
APP_ID = "cli_a929838abb389bc6"
APP_SECRET = "3vasdyspNoUPXCL6TniyLdkQbLqmPqEU"

def get_tenant_token():
    url = "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal"
    payload = {"app_id": APP_ID, "app_secret": APP_SECRET}
    response = requests.post(url, json=payload)
    return response.json()["tenant_access_token"] if response.status_code == 200 else None

def update_group_visibility(token, chat_id):
    """修改群为企业内公开可搜索"""
    url = f"https://open.feishu.cn/open-apis/im/v1/chats/{chat_id}"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json; charset=utf-8"
    }
    payload = {
        "join_message_visibility": "all_members",
        "leave_message_visibility": "all_members",
        "membership_approval": "no_approval",
        "search_visibility": "only_org",  # 企业内可搜索
        "edit_permission": "all_members",
        "share_permission": "all_members",
        "add_member_permission": "all_members",
        "at_all_permission": "all_members"
    }
    response = requests.patch(url, headers=headers, json=payload)
    print("修改群可见性结果：")
    if response.status_code == 200:
        data = response.json()
        if data["code"] == 0:
            print("✅ 群可见性修改成功！现在企业内所有人都可以搜索到这个群，无需审核直接加入")
            print(f"群名称：研发项目工作群")
            print(f"群ID：{chat_id}")
            print(f"加入链接：https://applink.feishu.cn/client/chat/chatter/{chat_id}")
            return True
        else:
            print(f"修改失败：{data['msg']}")
            return False
    else:
        print(f"请求失败: {response.status_code}, {response.text}")
        return False

def send_group_link_to_user(token, user_id, chat_id):
    """直接给用户发群链接"""
    url = "https://open.feishu.cn/open-apis/im/v1/messages"
    headers = {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json; charset=utf-8"
    }
    params = {"receive_id_type": "open_id"}
    payload = {
        "receive_id": user_id,
        "msg_type": "text",
        "content": json.dumps({"text": f"👉 全新研发项目工作群已设置为企业公开可搜索，您可以直接点击链接加入：\nhttps://applink.feishu.cn/client/chat/chatter/{chat_id}\n现在所有人都能搜到这个群了，无需审核直接加入。"})
    }
    response = requests.post(url, headers=headers, params=params, json=payload)
    if response.status_code == 200 and response.json()["code"] == 0:
        print("\n✅ 群链接已发送到您的私信")
        return True
    return False

if __name__ == "__main__":
    token = get_tenant_token()
    if token:
        # 之前创建的全新研发项目工作群ID
        chat_id = "oc_deb45ba0f817a83fc9588a36cbc9c7b6"
        if update_group_visibility(token, chat_id):
            send_group_link_to_user(token, "ou_5724d98779c961cde9b86d85a614dc3c", chat_id)

