    url = "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal"
    payload = {"app_id": APP_ID, "app_secret": APP_SECRET}
    response = requests.post(url, json=payload)
    return response.json()["tenant_access_token"] if response.status_code == 200 else None

def recall_last_message(token, chat_id):
    """撤回群里最后一条我发的消息"""
    # 先获取最近的消息
    url = f"https://open.feishu.cn/open-apis/im/v1/messages"
    headers = {"Authorization": f"Bearer {token}"}
    params = {
        "container_id_type": "chat",
        "container_id": chat_id,
        "page_size": 5
    }
    response = requests.get(url, headers=headers, params=params)
    if response.status_code == 200:
        data = response.json()
        if data["code"] == 0 and data["data"]["items"]:
            for msg in data["data"]["items"]:
                if msg["sender"]["sender_type"] == "app" and msg["sender"]["id"] == APP_ID:
                    # 找到我发的消息，撤回
                    recall_url = f"https://open.feishu.cn/open-apis/im/v1/messages/{msg['message_id']}/recall"
                    recall_resp = requests.post(recall_url, headers=headers)
                    if recall_resp.status_code == 200 and recall_resp.json()["code"] == 0:
                        print(f"✅ 已撤回消息：{msg['message_id']}")
                        return True
    print("撤回失败")
    return False

if __name__ == "__main__":
    token = get_tenant_token()
    if token:
        # 全员群ID
